            "type": "splunk.markdown"
        }
    },
    "dataSources": {
        "ds_8T1EljtZ": {
            "name": "Active Customers copy 1",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(118 + i*0.34 + (random()%30)/10, 1), delta=3.1 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_OxlytOEl": {
            "name": "Registrations by Country copy 6",
            "options": {
                "query": "| makeresults count=7 | streamstats count as r | eval country=mvindex(split(\"Brazil,International,Spain,Italy,Romania,Denmark,Mexico\",\",\"),r-1), count=tonumber(mvindex(split(\"41200,33800,15600,11200,7400,4100,3050\",\",\"),r-1)) | fields country count"
            },
            "type": "ds.search"
        },
        "ds_active": {
            "name": "Active Customers",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(118 + i*0.34 + (random()%30)/10, 1), delta=3.1 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_experience": {
            "name": "Customer Experience",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(97.0 + i*0.014 + (random()%5)/10, 1), delta=0.3 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_hwUWUm5w": {
            "name": "New Registrations copy 2",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(7000 + i*95 + (random()%150), 0), delta=62 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_iQP7vI3f": {
            "name": "Logins by Country copy 5",
            "options": {
                "query": "| makeresults count=8 | streamstats count as r | eval country=mvindex(split(\"International,Spain,Italy,Romania,Brazil,Denmark,France,Portugal\",\",\"),r-1), count=tonumber(mvindex(split(\"54100,26000,18400,14100,10800,6400,4200,3100\",\",\"),r-1)) | fields country count"
            },
            "type": "ds.search"
        },
        "ds_idwFKqmr": {
            "name": "Live Stakes copy 4",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(3.2 + i*0.05 + (random()%8)/100, 1), delta=2.8 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_logins_country": {
            "name": "Logins by Country",
            "options": {
                "query": "| makeresults count=8 | streamstats count as r | eval country=mvindex(split(\"International,Spain,Italy,Romania,Brazil,Denmark,France,Portugal\",\",\"),r-1), count=tonumber(mvindex(split(\"54100,26000,18400,14100,10800,6400,4200,3100\",\",\"),r-1)) | fields country count"
            },
            "type": "ds.search"
        },
        "ds_nNbe6CBf": {
            "name": "Customer Experience copy 3",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(96.0 + i*0.014 + (random()%5)/10, 1), delta=-0.3 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_regs": {
            "name": "New Registrations",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(7000 + i*95 + (random()%150), 0), delta=62 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_regs_country": {
            "name": "Registrations by Country",
            "options": {
                "query": "| makeresults count=7 | streamstats count as r | eval country=mvindex(split(\"Brazil,International,Spain,Italy,Romania,Denmark,Mexico\",\",\"),r-1), count=tonumber(mvindex(split(\"41200,33800,15600,11200,7400,4100,3050\",\",\"),r-1)) | fields country count"
            },
            "type": "ds.search"
        },
        "ds_stakes": {
            "name": "Live Stakes",
            "options": {
                "query": "| makeresults count=30 | streamstats count as i | eval _time=now()-(30-i)*180, value=round(3.2 + i*0.05 + (random()%8)/100, 1), delta=2.8 | fields _time value delta | sort _time"
            },
            "type": "ds.search"
        },
        "ds_sbg_cashout": {
            "name": "SBG Cashout",
            "options": {
                "query": "| makeresults count=7 | streamstats count as r | eval category=mvindex(split(\"SUCCESS,NOT_ELIGIBLE,MARKET_SUSPENDED,GENERAL_FAILURE,INVALID_QUOTE,BET_CLOSED,INVALID_RUNNER\",\",\"),r-1) | eval count=tonumber(mvindex(split(\"4800,72,21,11,7,5,3\",\",\"),r-1)) + (random()%21) - 10 | eval count=if(count<0,0,count) | eval delta=if(category=\"SUCCESS\",round((random()%12)/10,1),null()) | fields category count delta"
            },
            "type": "ds.search"
        },
        "ds_sbg_bingo": {
            "name": "SBG Bingo Game Play",
            "options": {
                "query": "| makeresults count=12 | streamstats count as r | eval category=mvindex(split(\"Fluffy Favourites,Rainbow Riches,Fruity Burst,Bouncy Balls,Enchanted Prince,Sky Premium Room,Shamans Dream,White Wizard,The Magical Jackpot,Fluffy Favorites Jackpot,Bonanza,Slingo\",\",\"),r-1) | eval count=tonumber(mvindex(split(\"5200,3100,2400,1900,1500,1200,950,800,600,450,300,220\",\",\"),r-1)) + (random()%201) - 100 | eval count=if(count<0,0,count) | fields category count"
            },
            "type": "ds.search"
        }
    },
